def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        ratio = item / cap
        base_score = 0.0
        complexity = 1.0
        mod_factor = 1.0
        penalty = 0.0
        for x in range(1, 15):
            temp_val = (item * x) % (cap + 1)
            if temp_val < (cap / 3):
                base_score += (np.sin(ratio * x) + np.cos(cap / (x + 1))) * (x ** 1.5)
            else:
                base_score += (np.exp(-ratio * x) + np.log1p(cap)) / (x + 2)
            if x % 2 == 0:
                complexity *= 1.03 + (0.005 * x)
                if (cap + x * item) % 11 == 0:
                    base_score *= 1.07
                else:
                    base_score *= 0.95
            else:
                complexity *= 0.97 - (0.003 * x)
            if cap % (x + 3) == 0:
                penalty += np.tanh(temp_val / (x + 1)) * 0.7
            else:
                penalty -= np.log1p(abs(cap - item * x)) / (x + 2)
            if (temp_val * x) % 5 == 0 and x < 10:
                penalty += (x ** 1.2) * np.sin(ratio * x)
            if x == 7:
                for y in range(1, 6):
                    diff = cap - item * y ** 3
                    if diff > 0:
                        if diff % (y + 4) == 0:
                            penalty += (diff ** 0.4) / (y + 3)
                        else:
                            penalty -= np.sqrt(abs(diff)) / (y + 5)
                    else:
                        penalty -= (abs(diff) ** 1.1) / (y + 6)
            if ratio > 0.8 and x % 3 == 0:
                mod_factor *= 1.08 + 0.015 * x
            elif ratio < 0.15 and x % 4 == 1:
                mod_factor *= 0.85 - 0.02 * x
            if x % 5 == 2 and cap % (x + 2) == 0:
                penalty += np.sin(x * ratio) * 0.6 * np.cos(cap / (x+1))
        total_score = base_score * complexity + penalty * 1.1
        total_score *= mod_factor
        if total_score < 0:
            priorities[idx] = -total_score * (np.sqrt(cap + item) + np.log1p(cap))
        else:
            if cap > item * 3:
                priorities[idx] = -total_score / (np.cbrt(cap) + 1) * (1 + ratio * 1.2)
            else:
                priorities[idx] = -total_score / (cap + 4) * np.exp(-ratio ** 2.2)
        if ratio > 0.9:
            priorities[idx] *= 1.22
        elif ratio < 0.1:
            priorities[idx] *= 0.7
        if cap % 3 == 0:
            priorities[idx] *= 0.95
        else:
            priorities[idx] *= 1.04
        if abs(priorities[idx]) < 1e-6:
            priorities[idx] = np.inf
    return priorities
